   850|
   851|    for (const uri of uris) {
   852|      if (uri.startsWith('file://') || uri.startsWith('content://') || uri.startsWith('ph://')) {
   853|        try {
   854|          const ext = getMimeAndExt(uri).ext;
   855|          const cachePath = `${FileSystem.cacheDirectory}queued_${Date.now()}_${Math.random().toString(36).substring(2, 6)}.${ext}`;
   856|          await FileSystem.copyAsync({ from: uri, to: cachePath });
   857|          const info = await FileSystem.getInfoAsync(cachePath);
   858|          if (info.exists) {
   859|            cachedUris.push(cachePath);
   860|            console.log('[PhotoUpload] Queued: cached file for offline retry:', cachePath);
   861|          }
   862|        } catch (copyErr) {
   863|          console.log('[PhotoUpload] Queued: could not cache file:', uri, (copyErr as Error)?.message);
   864|        }
   865|      } else if (uri.startsWith('data:image/')) {
   866|        try {
   867|          const match = uri.match(/^data:(image\/[^;]+);base64,(.+)$/);
   868|          if (match) {
   869|            const ext = getMimeAndExt(uri).ext;
   870|            const cachePath = `${FileSystem.cacheDirectory}queued_b64_${Date.now()}_${Math.random().toString(36).substring(2, 6)}.${ext}`;
   871|            await FileSystem.writeAsStringAsync(cachePath, match[2] ?? '', {
   872|              encoding: FileSystem.EncodingType.Base64,
   873|            });
   874|            const info = await FileSystem.getInfoAsync(cachePath);
   875|            if (info.exists) {
   876|              cachedUris.push(cachePath);
   877|              console.log('[PhotoUpload] Queued: base64 cached for offline retry:', cachePath);
   878|            }
   879|          }
   880|        } catch (b64Err) {
   881|          console.log('[PhotoUpload] Queued: could not cache base64:', (b64Err as Error)?.message);
   882|        }
   883|      }
