   885|
   886|    if (cachedUris.length === 0) return;
   887|
   888|    const existing = await AsyncStorage.getItem(OFFLINE_QUEUE_KEY);
   889|    const queue: QueuedUpload[] = existing ? JSON.parse(existing) : [];
   890|    cachedUris.forEach((localUri, i) => {
